// Normalize WooCommerce order.completed webhook payload
const order = $json.body || $json;
const firstName = order.billing?.first_name || '';
const lastName  = order.billing?.last_name  || '';
return {
  orderId:       String(order.id || order.number || ''),
  customerName:  [firstName, lastName].filter(Boolean).join(' ') || 'Customer',
  customerEmail: order.billing?.email || '',
  customerPhone: order.billing?.phone || '',
  products: (order.line_items || [])
    .map(item => ({ id: item.product_id, name: item.name || '', sku: item.sku || '' }))
    .filter(p => p.id)
};

// Normalize external POST body
const b = $json.body || $json;
return {
  orderId:       String(b.orderId || b.order_id || ''),
  customerName:  b.customerName  || b.customer_name || 'Customer',
  customerEmail: b.customerEmail || b.email        || '',
  customerPhone: b.customerPhone || b.phone        || '',
  products: (b.products || [])
    .map(p => ({ id: Number(p.id || p.product_id), name: p.name || '', sku: p.sku || '' }))
    .filter(p => p.id)
};

// ============================================================
// ⚙️  CONFIGURATION — edit all values marked with YOUR_
// ============================================================
const CONFIG = {
  // WooCommerce site URL (no trailing slash)
  siteUrl:    'https://YOUR_SITE_URL',

  // Shop name shown in emails and form
  shopName:   'YOUR_SHOP_NAME',

  // Logo image URL for email header (leave '' to hide)
  logoUrl:    'YOUR_LOGO_URL',

  // n8n public URL (where this n8n instance is hosted)
  n8nUrl:     'https://YOUR_N8N_URL',

  // Webhook paths — must match the webhook nodes below
  formWebhookPath:   'review-form',
  submitWebhookPath: 'submit-review',

  // Days until review link expires
  expiryDays: 30,

  // Set true to delay the email (configure Wait node)
  enableDelay: false,

  // Set true to shorten URLs via Dub.co
  enableUrlShortening: false,

  // Dub.co API key (only used if enableUrlShortening: true)
  dubApiKey: 'YOUR_DUB_API_KEY'
};

const order = $json;
const formId    = crypto.randomUUID();
const expiresAt = new Date(Date.now() + CONFIG.expiryDays * 86400000).toISOString();
const formUrl   = `${CONFIG.n8nUrl}/webhook/${CONFIG.formWebhookPath}?fid=${formId}`;

return { ...order, config: CONFIG, formId, formUrl, expiresAt, createdAt: new Date().toISOString() };

// Emit one item per product so HTTP Request loops
const data = $json;
return (data.products || []).map(p => ({ ...data, _product: p }));

// Merge WC API product details back with order data
const items   = $input.all();
const first   = items[0].json;
const baseKey = ['orderId','customerName','customerEmail','customerPhone','config','formId','formUrl','expiresAt','createdAt'];
const base    = {};
baseKey.forEach(k => { base[k] = first[k]; });

const products = items.map(item => {
  const wc  = item.json;          // WC API product response
  const src = item.json._product; // original product stub
  return {
    id:        wc.id   || src.id,
    name:      wc.name || src.name || '',
    sku:       wc.sku  || src.sku  || '',
    image:     (wc.images && wc.images[0]) ? wc.images[0].src : '',
    permalink: wc.permalink || ''
  };
}).filter(p => p.id);

return { ...base, products };

const row = $json;
if (!row.formId)                                   return [{ valid: false, reason: 'not_found'    }];
if (row.status === 'completed')                    return [{ valid: false, reason: 'already_used' }];
if (new Date(row.expiresAt) < new Date())          return [{ valid: false, reason: 'expired'      }];
return [{ ...row, products: JSON.parse(row.products || '[]'), valid: true }];

const d = $json;

const productCards = (d.products || []).map((p, i) => {
  const img = p.image
    ? `<img src="${p.image}" alt="${p.name.replace(/"/g,'')}" onerror="this.style.display='none'">`
    : '';
  return `
  <div class="card">
    <div class="product-row">
      ${img}
      <div class="product-name">${p.name}</div>
    </div>
    <input type="hidden" name="w_${i}" value="${p.id}">
    <input type="hidden" name="p_${i}" value="${p.name.replace(/"/g,'&quot;')}">
    <span class="label">Rating *</span>
    <div class="stars" id="stars_${i}">
      ${[5,4,3,2,1].map(v => `
        <span class="star" data-val="${v}" data-idx="${i}">★</span>`).join('')}
    </div>
    <input type="hidden" name="r_${i}" id="r_${i}" required>
    <span class="label" style="margin-top:14px;">Review <span style="color:#bbb;">(optional)</span></span>
    <textarea name="t_${i}" placeholder="What did you like or dislike?"></textarea>
  </div>`;
}).join('');

const html = `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="utf-8">
  <meta name="viewport" content="width=device-width,initial-scale=1">
  <title>Leave a Review</title>
  <style>
    *, *::before, *::after { box-sizing: border-box; margin:0; padding:0; }
    body { background:#f5f5f5; font-family:Arial,sans-serif; color:#111; min-height:100vh; }
    .wrap { max-width:580px; margin:0 auto; padding:40px 16px 80px; }
    .logo-row { text-align:center; padding-bottom:24px; }
    .logo-row img { max-height:44px; }
    h1 { font-size:22px; font-weight:normal; text-align:center; margin-bottom:6px; }
    .sub { font-size:14px; color:#888; text-align:center; margin-bottom:28px; }
    .card { background:#fff; border:1px solid #e4e4e4; padding:24px; margin-bottom:14px; }
    .product-row { display:flex; align-items:center; gap:14px; margin-bottom:18px; }
    .product-row img { width:52px; height:52px; object-fit:cover; border:1px solid #eee; flex-shrink:0; }
    .product-name { font-size:14px; color:#111; }
    .label { display:block; font-size:11px; color:#888; text-transform:uppercase; letter-spacing:.8px; margin-bottom:8px; }
    .stars { display:flex; gap:8px; margin-bottom:4px; }
    .star { font-size:30px; color:#ddd; cursor:pointer; user-select:none; transition:color .1s; }
    .star.active { color:#111; }
    textarea { width:100%; border:1px solid #ddd; padding:10px 12px; font-size:14px;
               resize:vertical; min-height:76px; font-family:Arial,sans-serif; margin-top:4px; }
    textarea:focus { outline:none; border-color:#111; }
    .err { font-size:12px; color:#c00; margin-top:8px; display:none; }
    .btn { display:block; width:100%; background:#111; color:#fff; border:none; padding:16px;
           font-size:13px; letter-spacing:1.5px; text-transform:uppercase; cursor:pointer; margin-top:22px; }
    .btn:hover { background:#333; }
    .btn:disabled { opacity:.5; cursor:default; }
    .success { display:none; text-align:center; padding:80px 20px; }
    .success h2 { font-size:20px; font-weight:normal; margin-bottom:10px; }
    .success p { font-size:14px; color:#888; }
  </style>
</head>
<body>
<div class="wrap">
  <div class="logo-row">
    <img src="" id="logo-img" onerror="this.style.display='none'" alt="">
  </div>
  <h1>Hi ${d.customerName}, how did we do?</h1>
  <p class="sub">Your honest review helps other shoppers</p>

  <form id="rf">
    <input type="hidden" name="formId"        value="${d.formId}">
    <input type="hidden" name="customerName"  value="${d.customerName.replace(/"/g,'&quot;')}">
    <input type="hidden" name="customerEmail" value="${d.customerEmail}">
    ${productCards}
    <p class="err" id="err-msg">Please rate all products before submitting.</p>
    <button type="submit" class="btn" id="submit-btn">Submit Reviews</button>
  </form>

  <div class="success" id="success-box">
    <h2>Thank you! 🎉</h2>
    <p>Your review has been submitted and will be published shortly.</p>
  </div>
</div>
<script>
  // Star rating interaction
  document.querySelectorAll('.stars').forEach(group => {
    const idx = group.id.replace('stars_','');
    group.querySelectorAll('.star').forEach(star => {
      star.addEventListener('click', () => {
        const val = star.dataset.val;
        document.getElementById('r_' + idx).value = val;
        group.querySelectorAll('.star').forEach(s =>
          s.classList.toggle('active', Number(s.dataset.val) <= Number(val))
        );
      });
    });
  });

  document.getElementById('rf').addEventListener('submit', async e => {
    e.preventDefault();
    const form = e.target;
    const data = Object.fromEntries(new FormData(form));
    const count = ${d.products.length};
    for (let i = 0; i < count; i++) {
      if (!data['r_' + i]) {
        document.getElementById('err-msg').style.display = 'block';
        return;
      }
    }
    document.getElementById('err-msg').style.display = 'none';
    const btn = document.getElementById('submit-btn');
    btn.disabled = true; btn.textContent = 'Submitting…';
    try {
      const res = await fetch(window.location.origin + '/webhook/submit-review', {
        method: 'POST',
        headers: {'Content-Type':'application/json'},
        body: JSON.stringify(data)
      });
      if (res.ok) {
        form.style.display = 'none';
        document.getElementById('success-box').style.display = 'block';
      } else { throw new Error('server'); }
    } catch {
      btn.disabled = false; btn.textContent = 'Submit Reviews';
      alert('Something went wrong. Please try again.');
    }
  });
</script>
</body>
</html>`;

return { html };

const reason = $json.reason || 'invalid';
const title = reason === 'already_used' ? 'Already Submitted' : 'Link Expired';
const msg   = reason === 'already_used'
  ? 'You have already submitted your review. Thank you!'
  : 'This review link has expired or is no longer valid.';
const html = `<!DOCTYPE html><html><head><meta charset="utf-8"><title>${title}</title>
<style>body{font-family:Arial,sans-serif;background:#f5f5f5;display:flex;align-items:center;justify-content:center;min-height:100vh;margin:0;}
.box{background:#fff;border:1px solid #e4e4e4;padding:60px 40px;text-align:center;max-width:420px;}
h2{font-weight:normal;font-size:20px;margin-bottom:10px;color:#111;}
p{color:#888;font-size:14px;line-height:1.6;}</style></head>
<body><div class="box"><h2>${title}</h2><p>${msg}</p></div></body></html>`;
return { html };

const row  = $json;
const body = $('Accept Review Submission').first().json.body || {};

if (!row.formId)                          return [{ valid: false, reason: 'not_found'    }];
if (row.status === 'completed')           return [{ valid: false, reason: 'already_used' }];
if (new Date(row.expiresAt) < new Date()) return [{ valid: false, reason: 'expired'      }];

const siteUrl = body.siteUrl || 'https://YOUR_SITE_URL'; // fallback

const reviews = [];
for (let i = 0; body['w_' + i] !== undefined; i++) {
  const wpId   = parseInt(body['w_' + i]);
  const rating = parseInt(body['r_' + i]) || 5;
  const text   = (body['t_' + i] || '').trim();
  if (!wpId) break;
  reviews.push({
    wpId,
    productName: body['p_' + i] || '',
    rating,
    review: text || `Rating: ${rating} out of 5`
  });
}

return [{
  valid:         true,
  formId:        row.formId,
  customerName:  body.customerName  || row.customerName  || 'Customer',
  customerEmail: body.customerEmail || row.customerEmail || '',
  siteUrl,
  reviews
}];
